import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  MessageSquare, Shield, 
  ChevronRight, Translate 
} from 'lucide-react';
import { io } from 'socket.io-client';

// Components
import HumanoidCanvas from '../components/HumanoidCanvas';
import LiveLogic from '../components/LiveLogic';
import XaiDashboard from '../components/XaiDashboard';

const API_URL = 'http://localhost:5000/api';
const api = axios.create({ baseURL: API_URL });
api.interceptors.request.use(config => {
    const token = localStorage.getItem('token');
    if (token) config.headers.Authorization = `Bearer ${token}`;
    return config;
});

const PatientPortal = () => {
    const [activeTab, setActiveTab] = useState('digital-twin');
    const [history, setHistory] = useState([]);
    const [prediction, setPrediction] = useState(null);
    const [loading, setLoading] = useState(false);
    const [selectedSymptoms, setSelectedSymptoms] = useState([]);
    const [socket, setSocket] = useState(null);
    const [translation, setTranslation] = useState(null);
    const [translating, setTranslating] = useState(false);

    // UI States
    const [bodyPartAction, setBodyPartAction] = useState(null);

    useEffect(() => {
        const s = io('http://localhost:5000');
        setSocket(s);

        // Initial data
        loadHistory();
        return () => s.disconnect();
    }, []);

    const loadHistory = async () => {
        try {
            const res = await api.get('/history');
            setHistory(res.data.data || []);
        } catch (e) {
            console.error("History sync failed");
        }
    };

    const handlePredict = async () => {
        if (selectedSymptoms.length === 0) return;
        setLoading(true);
        try {
            const res = await api.post('/predict', { symptoms: selectedSymptoms });
            setPrediction(res.data);
            setActiveTab('results');
            loadHistory();
        } catch (e) {
            console.error("Prediction failed");
        } finally {
            setLoading(false);
        }
    };

    const translateReport = async (lang) => {
        if (!prediction?.agentic_soap_note) return;
        setTranslating(true);
        try {
            const res = await api.post('/translate', { 
                text: prediction.agentic_soap_note, 
                targetLanguage: lang 
            });
            setTranslation(res.data.translation);
        } catch (e) {
            console.error("Translation error");
        } finally {
            setTranslating(false);
        }
    };

    const toggleSymptom = (s) => {
        setSelectedSymptoms(prev => 
            prev.includes(s) ? prev.filter(x => x !== s) : [...prev, s]
        );
    };

    const onSelectBodyPart = (part) => {
        setBodyPartAction(part);
        // Map body parts to common symptoms for the demo
        // Map body parts to common symptoms for the demo
        // Auto-select symptoms based on body part mapping for dynamic feel
        // Auto-select symptoms based on body part mapping for dynamic feel
    };

    return (
        <div className="min-h-screen bg-[#050510] text-white flex p-4 lg:p-8 gap-8 overflow-hidden font-['Outfit']">
            {/* Real-time Side Log */}
            <div className="hidden xl:block w-80 h-full">
                <LiveLogic socket={socket} />
            </div>

            {/* Main Interactive Core */}
            <main className="flex-1 flex flex-col gap-6 relative">
                {/* Header Navigation (Neo-Skeuomorphic) */}
                <header className="flex items-center justify-between px-8 py-4 bg-white/5 backdrop-blur-3xl border border-white/10 rounded-[30px] shadow-2xl">
                    <div className="flex items-center gap-4">
                        <div className="w-12 h-12 rounded-full bg-gradient-to-tr from-cyan-500 to-blue-600 flex items-center justify-center">
                            <Shield className="text-white w-6 h-6" />
                        </div>
                        <div>
                            <h1 className="text-xl font-bold tracking-tight">VITA-CORE <span className="text-cyan-400">OS 2.0</span></h1>
                            <p className="text-[10px] text-white/40 uppercase tracking-widest font-black">Agentic Health Management</p>
                        </div>
                    </div>

                    <nav className="flex gap-2">
                        {['digital-twin', 'results', 'timeline'].map(tab => (
                            <button 
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                className={`px-6 py-2 rounded-2xl text-sm font-bold transition-all duration-300 ${
                                    activeTab === tab 
                                    ? 'bg-white/10 shadow-[inset_0_2px_10px_rgba(255,255,255,0.1)] text-cyan-400' 
                                    : 'text-white/40 hover:text-white hover:bg-white/5'
                                }`}
                            >
                                {tab.split('-').join(' ').toUpperCase()}
                            </button>
                        ))}
                    </nav>
                </header>

                <div className="flex-1 overflow-hidden relative">
                    <AnimatePresence mode="wait">
                        {activeTab === 'digital-twin' && (
                            <motion.div 
                                key="twin"
                                initial={{ opacity: 0, scale: 0.95 }}
                                animate={{ opacity: 1, scale: 1 }}
                                exit={{ opacity: 0, scale: 1.05 }}
                                className="h-full grid grid-cols-1 lg:grid-cols-3 gap-6"
                            >
                                {/* 3D Canvas */}
                                <div className="lg:col-span-2 relative bg-gradient-to-b from-white/5 to-transparent rounded-[40px] border border-white/5 overflow-hidden group">
                                    <HumanoidCanvas onSelectPart={onSelectBodyPart} />
                                    <div className="absolute top-8 left-8">
                                        <div className="flex items-center gap-3 bg-slate-900/80 backdrop-blur-xl px-6 py-3 rounded-2xl border border-white/10">
                                            <div className="w-2 h-2 rounded-full bg-cyan-400 animate-ping" />
                                            <span className="text-xs font-bold uppercase tracking-widest text-cyan-400">Digital Twin Active</span>
                                        </div>
                                    </div>

                                    {bodyPartAction && (
                                        <motion.div 
                                            initial={{ opacity: 0, y: 20 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            className="absolute bottom-12 left-1/2 -translate-x-1/2 bg-slate-900/90 backdrop-blur-2xl p-6 rounded-3xl border border-cyan-500/30 shadow-[0_0_50px_rgba(0,243,255,0.2)] w-96"
                                        >
                                            <h4 className="text-sm font-bold text-center mb-4 uppercase tracking-widest">Analyze {bodyPartAction}?</h4>
                                            <div className="flex flex-wrap gap-2 justify-center mb-6">
                                                {['itching', 'skin_rash', 'stomach_pain', 'vomiting', 'fatigue', 'weight_loss'].slice(0, 4).map(s => (
                                                    <button 
                                                        key={s}
                                                        onClick={() => toggleSymptom(s)}
                                                        className={`px-4 py-2 rounded-xl text-[10px] font-bold border transition-all ${
                                                            selectedSymptoms.includes(s) 
                                                            ? 'bg-cyan-500 border-cyan-400 text-white' 
                                                            : 'bg-white/5 border-white/10 text-white/60'
                                                        }`}
                                                    >
                                                        {s.replace('_', ' ').toUpperCase()}
                                                    </button>
                                                ))}
                                            </div>
                                            <button 
                                                onClick={handlePredict}
                                                disabled={loading || selectedSymptoms.length === 0}
                                                className="w-full py-4 bg-gradient-to-r from-cyan-600 to-blue-700 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-lg hover:shadow-cyan-500/20 active:scale-95 transition-all"
                                            >
                                                {loading ? 'Processing Neural Path...' : 'Initiate AI Assessment'}
                                            </button>
                                        </motion.div>
                                    )}
                                </div>

                                {/* Quick Stats Section */}
                                <div className="space-y-6">
                                    <div className="bg-white/5 p-8 rounded-[40px] border border-white/10">
                                        <h3 className="text-xs font-bold text-white/40 uppercase tracking-[0.2em] mb-6">Vitals Status</h3>
                                        <div className="space-y-6">
                                            {[
                                                { label: 'Neural Sync', value: '98%', color: '#00f3ff' },
                                                { label: 'FHIR Health', value: 'Optimal', color: '#10b981' },
                                                { label: 'Risk Factor', value: 'Calculating', color: '#f59e0b' }
                                            ].map(stat => (
                                                <div key={stat.label} className="flex flex-col gap-2">
                                                    <div className="flex justify-between items-end">
                                                        <span className="text-xs font-medium text-white/60">{stat.label}</span>
                                                        <span className="text-sm font-bold" style={{ color: stat.color }}>{stat.value}</span>
                                                    </div>
                                                    <div className="h-1 bg-white/5 rounded-full overflow-hidden">
                                                        <div className="h-full w-2/3" style={{ backgroundColor: stat.color }} />
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    <div className="p-8 bg-gradient-to-br from-indigo-500/20 to-blue-600/20 border border-white/10 rounded-[40px] group transition-all cursor-pointer hover:border-cyan-500/50">
                                        <div className="flex justify-between items-start mb-6">
                                            <div className="p-3 bg-white/10 rounded-2xl">
                                                <Translate className="text-cyan-400 w-5 h-5" />
                                            </div>
                                            <ChevronRight className="text-white/20 group-hover:text-cyan-400 transition-colors" />
                                        </div>
                                        <h3 className="font-bold text-lg leading-tight">Gemini Multilingual Hub</h3>
                                        <p className="text-xs text-white/40 mt-2 leading-relaxed">Translate complex clinical diagrams and reports into 40+ languages instantly.</p>
                                    </div>
                                </div>
                            </motion.div>
                        )}

                        {activeTab === 'results' && prediction && (
                            <motion.div 
                                key="results"
                                initial={{ opacity: 0, x: 50 }}
                                animate={{ opacity: 1, x: 0 }}
                                className="h-full flex flex-col gap-6 overflow-y-auto pr-4"
                            >
                                {/* Augmented Intelligence Banner */}
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                    <div className="md:col-span-2 p-10 bg-gradient-to-r from-cyan-600/20 to-blue-700/20 rounded-[40px] border border-cyan-500/20 flex items-center gap-8">
                                        <div className="flex flex-col items-center gap-4">
                                            <div className="w-32 h-32 rounded-full border-4 border-cyan-400/30 flex items-center justify-center relative">
                                                <span className="text-3xl font-black text-cyan-400">{prediction.final_prediction.confidence.toFixed(0)}%</span>
                                                <div className="absolute inset-0 rounded-full border-4 border-cyan-400 border-t-transparent animate-spin" />
                                            </div>
                                            <span className="text-[10px] font-black uppercase tracking-widest text-cyan-400/60">Confidence Score</span>
                                        </div>
                                        <div>
                                            <h2 className="text-4xl font-black tracking-tight mb-2 uppercase">{prediction.final_prediction.disease}</h2>
                                            <div className="flex gap-2">
                                                <span className="px-4 py-1 bg-white/10 rounded-full text-[10px] font-bold uppercase tracking-widest">Random Forest Optimized</span>
                                                <span className="px-4 py-1 bg-emerald-500/20 text-emerald-400 rounded-full text-[10px] font-bold uppercase tracking-widest">FHIR Compliant</span>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="bg-slate-900 border border-white/10 rounded-[40px] p-8 flex flex-col justify-center gap-6">
                                        <h3 className="text-xs font-bold text-white/40 uppercase tracking-widest">Related Symptoms (GNN)</h3>
                                        <div className="flex flex-col gap-3">
                                            {prediction.related_symptoms?.map(s => (
                                                <div key={s} className="flex items-center gap-3 group">
                                                    <div className="w-1.5 h-1.5 rounded-full bg-yellow-500 group-hover:scale-150 transition-transform" />
                                                    <span className="text-sm font-medium text-white/80">{s.replace('_', ' ')}</span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </div>

                                {/* XAI Dashboard */}
                                <XaiDashboard data={prediction.xai_explanation} causal={prediction.causal_insight} />

                                {/* Clinical SOAP Note (Gemini Powered) */}
                                <div className="bg-white/5 border border-white/10 rounded-[40px] overflow-hidden">
                                    <div className="p-8 border-b border-white/10 flex justify-between items-center bg-white/5">
                                        <div className="flex items-center gap-4">
                                            <MessageSquare className="text-cyan-400 w-6 h-6" />
                                            <div>
                                                <h3 className="font-bold text-lg">Agentic Clinical SOAP Note</h3>
                                                <p className="text-[10px] text-white/40 uppercase font-black">Generated by Gemini 1.5 Pro</p>
                                            </div>
                                        </div>
                                        <div className="flex gap-2">
                                            {['Hindi', 'Spanish', 'French'].map(lang => (
                                                <button 
                                                    key={lang}
                                                    onClick={() => translateReport(lang)}
                                                    className="px-4 py-2 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl text-[10px] font-black uppercase transition-all"
                                                >
                                                    {lang}
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                    <div className="p-10 text-white/70 leading-relaxed font-light text-lg">
                                        {translating ? (
                                            <div className="animate-pulse space-y-4">
                                                <div className="h-4 bg-white/10 rounded w-3/4" />
                                                <div className="h-4 bg-white/10 rounded w-1/2" />
                                                <div className="h-4 bg-white/10 rounded w-5/6" />
                                            </div>
                                        ) : (
                                            <div className="whitespace-pre-line">
                                                {translation || prediction.agentic_soap_note}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </motion.div>
                        )}

                        {activeTab === 'timeline' && (
                            <motion.div 
                                key="timeline"
                                initial={{ opacity: 0, y: 30 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="p-8 bg-white/5 rounded-[40px] border border-white/10 h-full overflow-hidden flex flex-col"
                            >
                                <h2 className="text-2xl font-black mb-8">Clinical Analysis History</h2>
                                <div className="flex-1 overflow-y-auto space-y-4 pr-4 custom-scrollbar">
                                    {history.map((h, i) => (
                                        <div key={h._id || i} className="group p-6 bg-slate-900/50 hover:bg-slate-900 border border-white/5 hover:border-cyan-500/30 rounded-3xl transition-all flex items-center justify-between">
                                            <div className="flex items-center gap-6">
                                                <div className="w-12 h-12 rounded-2xl bg-white/5 flex flex-col items-center justify-center border border-white/10">
                                                    <span className="text-[10px] font-black text-white/40">{new Date(h.timestamp || h.effectiveDateTime).getDate()}</span>
                                                    <span className="text-[10px] font-black text-cyan-400 uppercase">{new Date(h.timestamp || h.effectiveDateTime).toLocaleString('default', { month: 'short' })}</span>
                                                </div>
                                                <div>
                                                    <h4 className="font-bold text-lg tracking-tight uppercase">{h.predictedDisease || h.conclusion}</h4>
                                                    <p className="text-xs text-white/40">{h.symptoms?.length || h.result?.length || 0} Symptoms Analyzed</p>
                                                </div>
                                            </div>
                                            <div className="text-right">
                                                <div className="text-xl font-black text-white">{h.confidence?.toFixed(1) || h.result?.[0]?.valueQuantity?.value?.toFixed(1) || 0}%</div>
                                                <div className="text-[10px] font-black uppercase text-cyan-400/60 tracking-widest">Confidence</div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>
            </main>

            <style>{`
                .custom-scrollbar::-webkit-scrollbar { width: 4px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 10px; }
                .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(0,243,255,0.3); }
            `}</style>
        </div>
    );
};

export default PatientPortal;
